patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 6fe969358185..ac0e81b7ce8e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -853,6 +853,7 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();
@@ -1004,9 +1005,39 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+  // add (umax X, C1), C2 --> usub.sat X, C1  when C2 == -C1.
+  // add (umax C1, X), C2 --> usub.sat X, C1  when C2 == -C1.
+  if (Op0->hasOneUse()) {
+    const APInt *C1;
+    Value *X;
+    CallInst *UMax = nullptr;
+    
+    // Check for umax(X, C1) where C1 is constant
+    if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::umax>(m_Value(X), m_APInt(C1)))) ||
+        match(Op0, m_OneUse(m_Intrinsic<Intrinsic::umax>(m_APInt(C1), m_Value(X))))) {
+      UMax = cast<CallInst>(Op0);
+      
+      // Check if the add constant is the negation of C1
+      if (*C == -*C1) {
+        // Transform to usub.sat(X, C1)
+        CallInst *USubSat = Builder.CreateBinaryIntrinsic(
+            Intrinsic::usub_sat, X, ConstantInt::get(Ty, *C1));
+        
+        // The umax is now dead since it only had this one use
+        // Mark it for deletion
+        if (UMax->hasOneUse()) {
+          UMax->eraseFromParent();
+        }
+        
+        return USubSat;
+      }
+    }
+  }
+
   return nullptr;
 }

+
 // match variations of a^2 + 2*a*b + b^2
 //
 // to reuse the code between the FP and Int versions, the instruction OpCodes
